     * Validates that the URL uses an allowed protocol and does not resolve to an internal address.
     * @param url The URL to validate
     * @throws IOException If the URL is invalid or points to an internal resource
     */
    private void validateUrl(URL url) throws IOException {
        // Validate protocol is HTTP/HTTPS
        String protocol = url.getProtocol().toLowerCase();
        if (!ALLOWED_PROTOCOLS.contains(protocol)) {
            throw new IOException("Disallowed protocol '" + protocol + "' for URL: " + url);
        }

        // Resolve all IPs for the host and ensure none are internal (prevents SSRF)
        InetAddress[] addresses = InetAddress.getAllByName(url.getHost());
        for (InetAddress address : addresses) {
            if (address.isLoopbackAddress() || address.isSiteLocalAddress() ||
                address.isLinkLocalAddress() || address.isAnyLocalAddress() ||
                isUniqueLocalAddress(address)) {
                throw new IOException("URL " + url + " resolves to internal address: " + address.getHostAddress());
            }
        }
