     * Checks if the HTTP response code is a redirect (3xx).
     * @param responseCode HTTP response code
     * @return true if it's a redirect code, false otherwise
     */
    private boolean isRedirect(int responseCode) {
        return responseCode == HttpURLConnection.HTTP_MOVED_PERM ||
               responseCode == HttpURLConnection.HTTP_MOVED_TEMP ||
               responseCode == HttpURLConnection.HTTP_SEE_OTHER ||
               responseCode == 307 || // Temporary Redirect (preserves method)
               responseCode == 308;   // Permanent Redirect (preserves method)
