     * Checks if the address is an IPv6 Unique Local Address (ULA, fc00::/7).
     * @param address The InetAddress to check
     * @return true if it's a ULA, false otherwise
     */
    private boolean isUniqueLocalAddress(InetAddress address) {
        if (address instanceof Inet6Address) {
            byte[] bytes = address.getAddress();
            // ULA range is fc00::/7 (first 7 bits are 1111110)
            return (bytes[0] & 0xfe) == 0xfc;
        }
        return false;
    }

    /**
     * Input stream wrapper that limits the number of bytes read to prevent OOM from large files.
     */
    private static class LimitingInputStream extends FilterInputStream {
        private final long maxBytes;
        private long bytesRead;

        protected LimitingInputStream(InputStream in, long maxBytes) {
            super(in);
            this.maxBytes = maxBytes;
            this.bytesRead = 0;
        }

        @Override
        public int read() throws IOException {
            int b = super.read();
            if (b!= -1) {
                bytesRead++;
                checkLimit();
            }
            return b;
        }

        @Override
        public int read(byte[] b, int off, int len) throws IOException {
            int read = super.read(b, off, len);
            if (read!= -1) {
                bytesRead += read;
                checkLimit();
            }
            return read;
        }

        /**
         * Checks if the number of bytes read exceeds the maximum allowed limit.
         * @throws IOException If the limit is exceeded
         */
        private void checkLimit() throws IOException {
            if (bytesRead > maxBytes) {
                throw new IOException("Input stream exceeded maximum allowed size of " + maxBytes + " bytes");
            }
        }
    }
}

